/* London Job Finder — static GitHub Pages version
   Loads pre-fetched jobs from data/jobs.json (generated by GitHub Actions every 6 hours).
   All filtering is done client-side — no server required.
*/

const PAGE_SIZE = 24;
let allJobs = [];        // all jobs from data/jobs.json
let filteredJobs = [];   // after keyword + tag + source filter
let displayedCount = 0;

// ── DOM refs ──
const searchBtn       = document.getElementById('search-btn');
const keywordInput    = document.getElementById('keyword-input');
const sourceFilter    = document.getElementById('source-filter');
const sortFilter      = document.getElementById('sort-filter');
const jobGrid         = document.getElementById('job-grid');
const loadingEl       = document.getElementById('loading');
const emptyEl         = document.getElementById('empty-state');
const errorBanner     = document.getElementById('error-banner');
const resultCount     = document.getElementById('result-count');
const loadMoreWrap    = document.getElementById('load-more-wrap');
const loadMoreBtn     = document.getElementById('load-more-btn');
const sourceStats     = document.getElementById('source-stats');
const template        = document.getElementById('job-card-template');
const hideSeniorBtn   = document.getElementById('hide-senior-btn');
const lastUpdatedBadge = document.getElementById('last-updated-badge');

// ── Senior-level title keywords ──
const SENIOR_KEYWORDS = [
  'senior', 'sr.', ' sr ', 'lead ', 'principal', 'head of', 'head,',
  'director', ' manager', 'managing director', 'vp ', 'svp', 'evp', 'avp',
  'vice president', 'chief ', 'partner', 'c-suite',
  'managing partner', 'managing consultant',
];

let hideSenior = true;

function isSeniorRole(title) {
  const t = title.toLowerCase();
  return SENIOR_KEYWORDS.some(kw => t.includes(kw));
}

function getVisibleJobs() {
  if (!hideSenior) return filteredJobs;
  return filteredJobs.filter(j => !isSeniorRole(j.title));
}

// ── Tag colours ──
const TAG_CLASSES = {
  'Graduate':         'tag-graduate',
  'Data & Analytics': 'tag-data',
  'Finance':          'tag-finance',
  'Banking':          'tag-banking',
  'Consulting':       'tag-consulting',
  'Quantitative':     'tag-quant',
};

// ── Load jobs from static JSON on page load ──
async function loadJobs() {
  loadingEl.classList.remove('hidden');
  jobGrid.innerHTML = '';
  resultCount.textContent = '';
  errorBanner.classList.add('hidden');
  emptyEl.classList.add('hidden');
  loadMoreWrap.classList.add('hidden');

  try {
    const res = await fetch('data/jobs.json');
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();

    allJobs = data.jobs || [];

    // Show last updated badge
    if (data.last_updated) {
      const d = new Date(data.last_updated);
      const ago = Math.round((Date.now() - d) / 60000);
      const label = ago < 60
        ? `Updated ${ago}m ago`
        : ago < 1440
          ? `Updated ${Math.floor(ago / 60)}h ago`
          : `Updated ${Math.floor(ago / 1440)}d ago`;
      lastUpdatedBadge.textContent = '🔄 ' + label;
    }

    // Show source stats
    if (data.meta) {
      const m = data.meta;
      sourceStats.innerHTML = `
        Searching <strong>${m.total_companies}</strong> company career pages<br>
        🟦 Greenhouse: ${m.greenhouse_count} companies<br>
        🟣 Lever: ${m.lever_count} companies<br>
        🟠 Ashby: ${m.ashby_count} companies<br>
        🟩 Workday: ${m.workday_count} companies<br>
        ${m.adzuna_enabled ? '🟡 Adzuna: ✅ enabled' : '⚪ Adzuna: disabled'}<br>
        🔵 Find a Job (Gov.uk): ✅ enabled<br>
        🔴 The Muse: ✅ enabled
      `;
    }

    applyFilters();

  } catch (err) {
    loadingEl.classList.add('hidden');
    errorBanner.textContent = `Could not load jobs: ${err.message}`;
    errorBanner.classList.remove('hidden');
  }
}

// ── Apply keyword + tag + source filters client-side ──
function applyFilters() {
  const keywords = keywordInput.value.trim()
    ? keywordInput.value.trim().toLowerCase().split(/\s+/)
    : [];

  const checkedTags = [...document.querySelectorAll('.tag-filter:checked')]
    .map(el => el.value);
  const filterTags = checkedTags.length < 6 ? new Set(checkedTags) : null;

  const filterSource = sourceFilter.value || null;

  filteredJobs = allJobs.filter(job => {
    // Keyword match
    if (keywords.length) {
      const combined = (job.title + ' ' + job.company + ' ' + (job.department || '')).toLowerCase();
      if (!keywords.every(kw => combined.includes(kw))) return false;
    }
    // Tag filter
    if (filterTags && !job.tags?.some(t => filterTags.has(t))) return false;
    // Source filter
    if (filterSource && job.source_system !== filterSource) return false;

    return true;
  });

  filteredJobs = sortJobs(filteredJobs);

  loadingEl.classList.add('hidden');
  displayedCount = 0;

  const visible = getVisibleJobs();
  if (visible.length === 0) {
    emptyEl.classList.remove('hidden');
    resultCount.textContent = '0 results';
  } else {
    emptyEl.classList.add('hidden');
    updateResultCount();
    renderPage();
  }
}

// ── Sort ──
function sortJobs(jobs) {
  const mode = sortFilter.value;
  return [...jobs].sort((a, b) => {
    if (mode === 'company') return a.company.localeCompare(b.company);
    if (mode === 'title')   return a.title.localeCompare(b.title);
    return (a.days_ago ?? 999) - (b.days_ago ?? 999);
  });
}

function updateResultCount() {
  const visible = getVisibleJobs();
  const hidden  = filteredJobs.length - visible.length;
  let text = `${visible.length} result${visible.length !== 1 ? 's' : ''}`;
  if (hidden > 0) text += ` <span class="count-muted">(${hidden} senior roles hidden)</span>`;
  resultCount.innerHTML = text;
}

function renderPage() {
  const visible = getVisibleJobs();
  const slice   = visible.slice(displayedCount, displayedCount + PAGE_SIZE);
  slice.forEach(job => jobGrid.appendChild(buildCard(job)));
  displayedCount += slice.length;

  if (displayedCount < visible.length) {
    loadMoreWrap.classList.remove('hidden');
    loadMoreBtn.textContent = `Load More (${visible.length - displayedCount} remaining)`;
  } else {
    loadMoreWrap.classList.add('hidden');
  }
}

function reRender() {
  jobGrid.innerHTML = '';
  displayedCount = 0;
  const visible = getVisibleJobs();
  if (visible.length === 0) {
    emptyEl.classList.remove('hidden');
  } else {
    emptyEl.classList.add('hidden');
    renderPage();
  }
  updateResultCount();
}

// ── Build a job card from template ──
function buildCard(job) {
  const clone = template.content.cloneNode(true);

  const avatar = clone.querySelector('.company-avatar');
  const initials = job.company
    .split(' ')
    .slice(0, 2)
    .map(w => w[0] || '')
    .join('')
    .toUpperCase();
  avatar.textContent = initials;
  avatar.style.background = avatarGradient(job.company);

  clone.querySelector('.company-name').textContent = job.company;
  clone.querySelector('.location-text').textContent = job.location;
  clone.querySelector('.job-title').textContent = job.title;

  if (job.department) {
    clone.querySelector('.department-line').textContent = job.department;
  }

  const badge = clone.querySelector('.days-badge');
  const d = job.days_ago ?? 99;
  if (d <= 7)       { badge.textContent = d === 0 ? 'Today' : `${d}d ago`; badge.classList.add('fresh'); }
  else if (d <= 30) { badge.textContent = `${d}d ago`; badge.classList.add('recent'); }
  else              { badge.textContent = job.posted_date || `${d}d ago`; badge.classList.add('older'); }

  const tagsEl = clone.querySelector('.card-tags');
  (job.tags || []).forEach(tag => {
    const span = document.createElement('span');
    span.className = `tag ${TAG_CLASSES[tag] || 'tag-default'}`;
    span.textContent = tag;
    tagsEl.appendChild(span);
  });

  const sourceColor = {
    Greenhouse: '#00b4d8',
    Lever:      '#6c63ff',
    Ashby:      '#ff9800',
    Workday:    '#2e7d32',
    Adzuna:     '#ff6b35',
    FindAJob:   '#003078',
    TheMuse:    '#e91e63',
  };
  const sourceLabel = {
    Greenhouse: 'Greenhouse',
    Lever:      'Lever',
    Ashby:      'Ashby',
    Workday:    'Workday',
    Adzuna:     'Adzuna',
    FindAJob:   'Gov.uk',
    TheMuse:    'The Muse',
  };
  clone.querySelector('.source-dot').style.background =
    sourceColor[job.source_system] || '#aaa';
  clone.querySelector('.source-text').textContent =
    sourceLabel[job.source_system] || job.source_system || 'Company';

  const applyBtn = clone.querySelector('.apply-btn');
  applyBtn.href = job.url || '#';
  if (!job.url) applyBtn.style.opacity = '.4';

  return clone;
}

function avatarGradient(name) {
  const palettes = [
    ['#0a2342','#1565c0'], ['#1b5e20','#388e3c'], ['#4a148c','#7b1fa2'],
    ['#bf360c','#e64a19'], ['#006064','#00838f'], ['#e65100','#f57c00'],
    ['#880e4f','#c2185b'], ['#1a237e','#303f9f'], ['#33691e','#558b2f'],
  ];
  let hash = 0;
  for (let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + (hash << 5) - hash;
  const [a, b] = palettes[Math.abs(hash) % palettes.length];
  return `linear-gradient(135deg, ${a} 0%, ${b} 100%)`;
}

// ── Event listeners ──
searchBtn.addEventListener('click', applyFilters);
loadMoreBtn.addEventListener('click', renderPage);

keywordInput.addEventListener('keydown', e => {
  if (e.key === 'Enter') applyFilters();
});

sortFilter.addEventListener('change', () => {
  if (allJobs.length) {
    filteredJobs = sortJobs(filteredJobs);
    reRender();
  }
});

document.querySelectorAll('.tag-filter').forEach(cb => {
  cb.addEventListener('change', () => { if (allJobs.length) applyFilters(); });
});

sourceFilter.addEventListener('change', () => {
  if (allJobs.length) applyFilters();
});

hideSeniorBtn.addEventListener('click', () => {
  hideSenior = !hideSenior;
  hideSeniorBtn.classList.toggle('active', hideSenior);
  hideSeniorBtn.setAttribute('aria-pressed', hideSenior);
  if (allJobs.length) reRender();
});

// ── Init ──
loadJobs();
